import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface CurrentUV {
  uvIndex: number;
  riskCategory: string;
}

interface HourlyForecast {
  hour: string;
  uvIndex: number;
}

interface UVData {
  current: CurrentUV;
  hourlyForecast: HourlyForecast[];
}

export default function Widget() {
  const uvData = response.data as UVData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
              UV Index
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FFC107', mb: 0.5 }}>
              {uvData.current.uvIndex}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Risk: {uvData.current.riskCategory}
            </Typography>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: uvData.hourlyForecast.map(f => f.uvIndex),
                color: '#FF5722',
              },
            ]}
            xAxis={[
              {
                data: uvData.hourlyForecast.map(f => f.hour),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              },
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
